from agent import *from models.products import *def run(context, session):    session.browser.agent = 'Mozilla/4.0 (compatible; MSIE 6.0; Windows NT 5.0)'    session.queue(Request("http://ogrecave.com/reviews/index.shtml", max_age=0), process_reviewlist, {})def process_reviewlist(data, context, session):    for rev in data.xpath("//td[@bgcolor='#EDECA1']/a|//td[@bgcolor='#EDECA1']/p/a"):        name = rev.xpath("descendant::text()").string(multiple=True)        category = rev.xpath("preceding::table[1]//text()").string(multiple=True)        date = rev.xpath("preceding-sibling::b[1]//text()").string(multiple=True)        manufacturer_author = rev.xpath("following-sibling::text()[1]").string(multiple=True)        url = rev.xpath("@href").string()        if url and name and manufacturer_author:            manufacturer = re_search_once('\((.*)\)', manufacturer_author)            author = re_search_once('by\s(.*)$', manufacturer_author)            session.queue(Request(url, max_age=0), process_review, dict(name=name, category=category, date=date, manufacturer=manufacturer, author=author, url=url))def process_review(data, context, session):    product = Product()    product.name = context['name']    product.manufacturer = context['manufacturer']    product.category = context['category']    product.url = context['url']    product.ssid = product.url.split('/')[-1].split('.')[0]    review = Review()    review.type = 'pro'    review.title = data.xpath("//td[@background='/gifs/scrolltile.gif']//text()").string()    review.date = context['date']    review.url = product.url    review.ssid = product.ssid    review.authors.append(Person(name=context['author'], ssid=context['author']))    content = data.xpath("//td[@bgcolor='#EDECA1']").first()    if content:        ratings = content.xpath("p[regexp:test(normalize-space(.),'rating','i')]/following-sibling::p[1]//text()[normalize-space(.)]")        if not(ratings):            ratings = content.xpath("p[regexp:test(normalize-space(.),'rating','i')]//text()[normalize-space(.)]")        if ratings:            for rating in ratings.strings():                if rating:                    scoredict = {'A': 5, 'A-': 4.5, 'B+': 4.5, 'B': 4, 'B-': 3.5, 'C+': 3.5, 'C': 3, 'D': 2, 'E': 1}                    title = re_search_once('^([^:]*):', rating)                    score = re_search_once(':\s([A-B+B-C+DE])', rating)                    if not score:                        if ' of 5 – ' in rating:                            score_num = float(rating.split(' of 5 – ')[0])                    if title and re.search('Overall', title) and score:                        fscore = scoredict[score]                        review.grades.append(Grade(name=title.strip(), type='overall', value=fscore, best=5))                    elif title and score:                        fscore = scoredict[score]                        review.grades.append(Grade(name=title.strip(), value=fscore, best=5))                    if ' of 5 – ' in rating:                        if title and re.search('Overall', title) and score_num:                            review.grades.append(Grade(name=title.strip(), type='overall', value=score_num, best=5))                        elif title and score_num:                            review.grades.append(Grade(name=title.strip(), value=score_num, best=5))    if content:        ref = content.xpath("p[regexp:test(normalize-space(.),'Conclusion')]").first()        if ref:            conclusion = ref.xpath("b/following-sibling::node()/descendant-or-self::text()").string(multiple=True)            if not(conclusion):                conclusion = ''            for node in ref.xpath("following-sibling::p"):                if node.xpath("contains(.,'Links:')"):                    break                else:                    if node.xpath("descendant::text()[not(ancestor::b)]"):                        conclusion += node.xpath("descendant::text()[not(ancestor::b)]").string(multiple=True)        ref2 = content.xpath("p[2]").first()        if ref2:            excerpt = ref2.xpath("descendant::text()").string(multiple=True)            if not(excerpt):                excerpt = ''            for node in ref2.xpath("following-sibling::p"):                if node.xpath("contains(.,'Links:')"):                    break                else:                    if node.xpath("descendant::text()[not(ancestor::b)]"):                        excerpt += node.xpath("descendant::text()[not(ancestor::b)]").string(multiple=True)            if excerpt:                if ref:                    if conclusion:                        excerpt = excerpt.replace(conclusion, '')                review.properties.append(ReviewProperty(type='excerpt', value=excerpt))        if ref:            if conclusion:                if ratings:                    conclusion = conclusion.replace(ratings.string(multiple=True), '')                    conclusion.split('Overall:')[0]            review.properties.append(ReviewProperty(type='conclusion', value=conclusion))        product.reviews.append(review)        session.emit(product)